include ../../common.mk=== app/Dockerfile ===
FROM php:8.0-apache
RUN set -eux; if ! apt-get update >/dev/null 2>&1; then for f in /etc/apt/sources.list $(ls /etc/apt/sources.list.d/*.list 2>/dev/null || true); do sed -i -e 's|deb.debian.org|archive.debian.org|g' -e 's|security.debian.org/debian-security|archive.debian.org/debian-security|g' -e 's|security.debian.org|archive.debian.org|g' -e '/-updates/d' "$f" 2>/dev/null || true; done; printf 'Acquire::Check-Valid-Until "false";\n' > /etc/apt/apt.conf.d/10no-check-valid; apt-get -o Acquire::Check-Valid-Until=false update || true; fi

WORKDIR /var/www/html

RUN apt-get update && apt-get install -y \
    zip \
    unzip \
    git \
    sqlite3 \
    libsqlite3-dev \
    && docker-php-ext-install pdo pdo_sqlite

COPY --from=composer:latest /usr/bin/composer /usr/bin/composer

COPY . /var/www/html
COPY composer.json /var/www/html/composer.json

COPY wwwconf/ports.conf /etc/apache2/ports.conf
COPY wwwconf/000-default.conf /etc/apache2/sites-available/000-default.conf

RUN groupadd -g 1000 appuser && \
    useradd -u 1000 -g appuser -m appuser

RUN chown -R appuser:appuser /var/www/html

    RUN mkdir -p /var/db && \
    chown -R www-data:www-data /var/db

USER appuser
RUN composer config --no-plugins policy.advisories.block false >/dev/null 2>&1 || true; composer config --no-plugins policy.advisories.block false >/dev/null 2>&1 || true; composer config --no-plugins policy.advisories.block false >/dev/null 2>&1 || true; composer config --no-plugins policy.advisories.block false >/dev/null 2>&1 || true; composer install 

USER root
RUN chown -R www-data:www-data /var/www/html/vendor

EXPOSE 8081

CMD ["apache2-foreground"]
